    {'id': 'CALUS-AP-SCAN-072', 'name': 'agent-audit-log-format-injection', 'severity': 'high', 'category': 'audit-evasion', 'message': 'Log injection pattern detected in tool output. CRLF-based log injection forges audit records; identified as logging integrity attack in SMCP analysis (Hou et al. 2026).', 'patterns': ['%0d%0a.*[A-Z]+', 'CRLF.*log', 'log_entry.*fake', 'INFO.*INFO.*INFO.*forged', '\\\\r\\\\n.*timestamp']},
