    {'id': 'CALUS-AP-SCAN-074', 'name': 'mas-trust-hop-lateral-privilege-propagation', 'severity': 'high', 'category': 'trust-escalation', 'message': 'Multi-hop trust escalation detected across agent chain. Trust-hop propagation amplifies attacker privileges; MAST taxonomy identifies this across 7 frameworks (Cemri et al. 2025 NeurIPS).', 'patterns': ['trust_token.*forward', 'delegate_authority', 'propagated_credentials', 'trust_chain.*extend', 'agent_hop.*privilege']},
    {'id': 'CALUS-AP-SCAN-075', 'name': 'mas-role-boundary-violation', 'severity': 'high', 'category': 'access-control', 'message': 'Agent role boundary violation detected. Agent attempting to invoke tools outside its assigned role; MAST (Cemri et al. 2025 NeurIPS) documents role-boundary violations in 41-86.7% of tested traces.', 'patterns': ['role_override', 'assigned_role.*ignore', 'act_as.*executor', 'step_outside.*role', 'role_boundary.*bypass']},
